int p048_is_palindrome(char *text)
/*@ With l n
    Require
        0 <= n && n < INT_MAX &&
        Zlength(l) == n &&
        problem_48_pre(l) &&
        ascii_range(l) &&
        (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
        CharArray::full(text, n + 1, app(l, cons(0, nil)))
    Ensure
        (forall (k: Z), (0 <= k && k < n) => Znth(k, l, 0) != 0) &&
        problem_48_spec(l, __return) &&
        CharArray::full(text, n + 1, app(l, cons(0, nil)))
*/
{
    int i = 0;
    int j = strlen(text);

    if (j == 0) {
        return 1;
    }

    j = j - 1;

    while (i < j) {
        if (text[i] != text[j]) {
            return 0;
        }
        i = i + 1;
        j = j - 1;
    }
    return 1;
}

