/*@ Extern Coq (problem_15_pre: Z -> Prop)
               (problem_15_spec: Z -> list Z -> Prop)
               (sequence_prefix: Z -> list Z)
               (sequence_output: Z -> list Z)
               (sequence_output_bound: Z -> Prop)
               (base_digits: Z -> Z -> list Z)
               (base_count_state: Z -> Z -> Z -> Z -> Prop)
